# Fallback retrieval: retry with lower threshold if first search returns nothing
# Prevents the agent from giving 'I don't know' when relevant memory exists

def retrieve_with_fallback(
    query: str,
    collection: str,
    k: int = 5,
    thresholds: list[float] = [0.65, 0.55, 0.45],
) -> tuple[list[dict], float]:
    result = voyage.embed([query], model='voyage-3', input_type='query')
    query_vec = result.embeddings[0]

    for threshold in thresholds:
        hits = qdrant.search(
            collection,
            query_vector=query_vec,
            limit=k,
            score_threshold=threshold,
            with_payload=True,
        )
        if hits:
            return (
                [{'text': h.payload['text'], 'score': h.score} for h in hits],
                threshold,
            )

    return [], 0.0  # no memories found at any threshold

memories, used_threshold = retrieve_with_fallback(
    'Who was responsible for the deployment failure?',
    collection='memories',
)
if memories:
    print(f'Found {len(memories)} results at threshold {used_threshold}')
else:
    print('No relevant memories found — answering from model knowledge only')

# Deduplicate retrieved chunks that are near-duplicates of each other
# Prevents the same content from appearing twice in the context window
import numpy as np

def cosine_similarity(a: list[float], b: list[float]) -> float:
    va, vb = np.array(a), np.array(b)
    return float(np.dot(va, vb) / (np.linalg.norm(va) * np.linalg.norm(vb) + 1e-9))

def deduplicate_results(
    hits: list[dict],      # each has 'text', 'score', 'vector'
    sim_threshold: float = 0.92,
) -> list[dict]:
    kept: list[dict] = []
    for hit in hits:
        # Check if this hit is too similar to any already-kept result
        is_dup = any(
            cosine_similarity(hit['vector'], k['vector']) >= sim_threshold
            for k in kept
        )
        if not is_dup:
            kept.append(hit)
    return kept

# Usage: retrieve more candidates, then deduplicate down to k unique ones
def retrieve_unique(
    query: str,
    collection: str,
    k: int = 5,
    candidate_multiplier: int = 3,
) -> list[dict]:
    result = voyage.embed([query], model='voyage-3', input_type='query')
    query_vec = result.embeddings[0]

    # Retrieve 3× candidates
    hits = qdrant.search(
        collection, query_vector=query_vec,
        limit=k * candidate_multiplier,
        with_payload=True, with_vectors=True,
    )
    dicts = [
        {'text': h.payload['text'], 'score': h.score, 'vector': h.vector}
        for h in hits
    ]
    return deduplicate_results(dicts)[:k]
